package com.panini.back.dto; import jakarta.validation.constraints.NotBlank; public class AuthDtos { public static class RegisterRequest { @NotBlank(message = "Username is required") public String username; @NotBlank(message = "Password is required") public String password; @NotBlank(message = "Display name is required") public String displayName; } public static class LoginRequest { @NotBlank(message = "Username is required") public String username; @NotBlank(message = "Password is required") public String password; } public static class AuthResponse { public String token; public String username; public String displayName; public AuthResponse(String token,String username,String displayName){ this.token=token; this.username=username; this.displayName=displayName; } } }
